/* ─── CORNER SVG ─── */
function CornerSVG() {
  return (
    <svg viewBox="0 0 60 60" fill="none" stroke="currentColor" strokeWidth="1">
      <path d="M4 56L4 4L56 4" strokeDasharray="200"/>
      <path d="M4 30 Q18 18 30 4"/>
      <circle cx="4" cy="4" r="3" fill="currentColor" stroke="none"/>
      <circle cx="4" cy="56" r="2" fill="currentColor" stroke="none" opacity=".35"/>
      <circle cx="56" cy="4" r="2" fill="currentColor" stroke="none" opacity=".35"/>
    </svg>
  );
}

/* ─── MANDALA SVG ─── */
function MandalaSVG({size=500, op=1}) {
  return (
    <svg width={size} height={size} viewBox="0 0 500 500" fill="none" stroke="#C9A96E" strokeWidth=".7" opacity={op}>
      {[0,30,60,90,120,150].map(a=>(
        <g key={a} transform={`rotate(${a} 250 250)`}>
          <ellipse cx="250" cy="250" rx="195" ry="58"/>
          <ellipse cx="250" cy="250" rx="155" ry="38"/>
        </g>
      ))}
      {[0,45,90,135].map(a=>(
        <g key={a} transform={`rotate(${a} 250 250)`}>
          <line x1="250" y1="55" x2="250" y2="445"/>
        </g>
      ))}
      <circle cx="250" cy="250" r="195" strokeDasharray="4 9"/>
      <circle cx="250" cy="250" r="145" strokeDasharray="2 7"/>
      <circle cx="250" cy="250" r="90"/>
      <circle cx="250" cy="250" r="32"/>
      <circle cx="250" cy="250" r="8" fill="#C9A96E" stroke="none"/>
    </svg>
  );
}

/* ─── ICONS ─── */
function CalIcon() { return <svg viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2"/><path d="M16 2v4M8 2v4M3 10h18"/></svg>; }
function ClockIcon() { return <svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="9"/><path d="M12 6v6l4 2"/></svg>; }
function PinIcon() { return <svg viewBox="0 0 24 24"><path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7z"/><circle cx="12" cy="9" r="2.5"/></svg>; }

/* ─── FLOATING PETALS ─── */
function Petals() {
  const items = Array.from({length:16},(_,i)=>({
    id:i,
    left:`${4+Math.random()*92}%`,
    size:10+Math.random()*12,
    delay:Math.random()*12,
    dur:9+Math.random()*9,
    sym:['🌸','🌺','✿','❀','🪷','✾'][Math.floor(Math.random()*6)],
  }));
  return (
    <div style={{position:'fixed',inset:0,pointerEvents:'none',zIndex:1,overflow:'hidden'}}>
      {items.map(p=>(
        <div key={p.id} className="petal" style={{
          left:p.left,top:'-30px',fontSize:`${p.size}px`,
          animationDuration:`${p.dur}s`,animationDelay:`${p.delay}s`,opacity:.45,
        }}>{p.sym}</div>
      ))}
    </div>
  );
}

/* ─── GOLDEN DIVIDER ─── */
function GoldenDivider({text="✦"}) {
  return (
    <div className="golden-divider">
      <div className="gdiv-line"/><div className="gdiv-diamond"/>
      <div className="gdiv-text">{text}</div>
      <div className="gdiv-diamond"/><div className="gdiv-line"/>
    </div>
  );
}

/* ─── SCROLL REVEAL HOOK ─── */
function useReveal() {
  useEffect(()=>{
    const obs = new IntersectionObserver(entries=>{
      entries.forEach(e=>{ if(e.isIntersecting) e.target.classList.add('visible'); });
    },{threshold:.1});
    document.querySelectorAll('.reveal,.reveal-left,.reveal-right').forEach(el=>obs.observe(el));
    return ()=>obs.disconnect();
  },[]);
}

/* ─── COUNTDOWN ─── */
function useCountdown(target) {
  const [t,setT]=useState({});
  useEffect(()=>{
    const calc=()=>{
      const diff=new Date(target)-new Date();
      if(diff<=0) return setT({d:0,h:0,m:0,s:0});
      setT({d:Math.floor(diff/86400000),h:Math.floor((diff%86400000)/3600000),m:Math.floor((diff%3600000)/60000),s:Math.floor((diff%60000)/1000)});
    };
    calc(); const id=setInterval(calc,1000); return ()=>clearInterval(id);
  },[target]);
  return t;
}

